SELECT

FROM
    t_user


        AND user_id = #{userId}


        AND user_name LIKE CONCAT('%', #{userName}, '%')


        AND role = #{role}


        AND email LIKE CONCAT('%', #{email}, '%')


        AND tel LIKE CONCAT('%', #{tel}, '%')


        AND gender = #{gender}


        AND status = #{status}

     AND ${_nineAiGenerated} 

ORDER BY created_at DESC
